import React, { useEffect, useState } from "react";
import { api } from "../api";

export default function Recipes({ onError }) {
  const [data, setData] = useState({ at_risk_items: [], recipes: [] });

  async function load() {
    try {
      const res = await api.getRecipes();
      setData(res);
    } catch (e) {
      onError(e.message);
    }
  }

  useEffect(() => { load(); }, []);

  return (
    <div className="card">
      <h2>Recipes</h2>

      <h3>At-Risk Items (≤ 48h)</h3>
      {data.at_risk_items?.length ? (
        <ul>
          {data.at_risk_items.map((x, i)=><li key={i}>{x}</li>)}
        </ul>
      ) : <p className="small">No at-risk items right now.</p>}

      <h3>Recommended Recipes</h3>
      {data.recipes?.length ? data.recipes.map(r => (
        <div className="card" key={r.id}>
          <h3>{r.name}</h3>
          <div className="small">Uses at-risk items: <b>{r.uses_at_risk_count}</b></div>
          <p><b>Ingredients:</b> {r.ingredients.join(", ")}</p>
          <p className="small">{r.instructions}</p>
          {r.tags?.length ? <div className="small">Tags: {r.tags.join(", ")}</div> : null}
        </div>
      )) : <p className="small">No cookable recipes found (add more items or add more recipes).</p>}
    </div>
  );
}
